[CmdletBinding()]param([Parameter(Mandatory)][ValidateRange(1024,65535)][int]$Port,[string]$Root=(Join-Path $env:LOCALAPPDATA 'WukongCodexForge\app'))
$ErrorActionPreference='Stop';$pkg=Get-AppxPackage -Name 'OpenAI.Codex'|Select-Object -First 1;if(-not $pkg){throw 'Official OpenAI.Codex Store package was not found.'};$listen=Get-NetTCPConnection -LocalAddress '127.0.0.1' -LocalPort $Port -State Listen -ErrorAction SilentlyContinue|Select-Object -First 1;if(-not $listen){throw "No Codex CDP listener on 127.0.0.1:$Port. Launch Codex yourself with --remote-debugging-address=127.0.0.1 --remote-debugging-port=$Port, then rerun."};$proc=Get-Process -Id $listen.OwningProcess -ErrorAction Stop;if($proc.Path -notlike "$($pkg.InstallLocation)*"){throw 'Refusing CDP: listener process path is not inside the registered OpenAI.Codex package.'};Push-Location $Root;try{node runtime/injector.mjs --verify $Port;node runtime/injector.mjs --apply $Port themes/active.json}finally{Pop-Location}
